#!/usr/bin/env python3
# bench.py - 13-1 benchmark: O_SYNC x BUF_SIZE x filesystem
# Generated by Claude

import os, sys, subprocess, time, shutil, resource
from itertools import product

SCRIPT_DIR  = os.path.dirname(os.path.abspath(__file__))
INPUT       = os.path.join(SCRIPT_DIR, "inputfile.txt")
FILESYSTEMS = ["ext2", "ext3", "xfs", "btrfs"]
BUF_SIZES   = [1, 32, 1024]

if os.geteuid() != 0:
    sys.exit("Run with sudo")

# 計測ごとに上書きするバイナリ。名前は固定
BIN = os.path.join(SCRIPT_DIR, "a.out")

def compile_binary(buf, sync):
    # -D BUF_SIZE=N でバッファサイズ、-D USE_SYNC で copy.c 内の #ifdef USE_SYNC が有効になる
    flags = [f"-D BUF_SIZE={buf}"] + (["-D USE_SYNC"] if sync else [])
    subprocess.run(["gcc", os.path.join(SCRIPT_DIR, "copy.c")] + flags + ["-o", BIN], check=True)

def measure(input_path, outdir):
    out = os.path.join(outdir, "out.txt")
    # /usr/bin/time -f "%e %U %S" で real・user・sys を stderr に出力させてパース
    r = subprocess.run(["/usr/bin/time", "-f", "%e %U %S", BIN, input_path, out],
                       capture_output=True, text=True)
    real, user, sys_ = map(float, r.stderr.strip().split())
    os.remove(out)
    return real, user, sys_

def setup_fs(fs):
    img = f"/tmp/bench_{fs}.img"   # ループデバイス用のイメージファイル
    mnt = f"/tmp/bench_mnt_{fs}"  # マウントポイント

    os.makedirs(mnt, exist_ok=True)

    # 2GB のゼロ埋めファイルを作成。これがループデバイスの「仮想ディスク」になる
    subprocess.run(["dd", "if=/dev/zero", f"of={img}", "bs=1M", "count=2048", "status=none"], check=True)

    # ファイルシステムごとのフォーマットコマンド
    # -F/-f はイメージファイルへの書き込みを強制するオプション
    cmds = {
        "ext2":  ["mkfs.ext2", "-q", "-F", img],
        "ext3":  ["mkfs.ext3", "-q", "-F", img],
        "xfs":   ["mkfs.xfs",  "-q", "-f", img],
        "btrfs": ["mkfs.btrfs","-q", img],
    }
    subprocess.run(cmds[fs], check=True)

    # -o loop でファイルをブロックデバイスとして扱い、通常のディレクトリにマウント
    subprocess.run(["mount", "-o", "loop", img, mnt], check=True)
    return img, mnt

def drop_caches():
    # drop_caches はダーティオブジェクトを解放しないため、先に sync でフラッシュする
    # 1: ページキャッシュを解放
    # 2: dentry・inode (slab) を解放
    # 3: 1+2 両方を解放  ← ベンチマーク前にキャッシュの影響を排除するためこれを使う
    # https://docs.kernel.org/admin-guide/sysctl/vm.html#drop-caches
    subprocess.run(["sync"], check=True)
    with open("/proc/sys/vm/drop_caches", "w") as f:
        f.write("3\n")

def teardown_fs(img, mnt):
    subprocess.run(["umount", mnt], check=True)
    os.remove(img)
    shutil.rmtree(mnt)

# --- 計測 ---
results = {}
for fs in FILESYSTEMS:
    print(f"[{fs}]", flush=True)
    img, mnt = setup_fs(fs)
    try:
        inp = os.path.join(mnt, "input.txt")
        shutil.copy(INPUT, inp)  # 入力ファイルを対象 FS 上に置く

        # BUF_SIZE x O_SYNC の全組み合わせを計測 (O_SYNC ありは ext2 のみ)
        sync_flags = [True, False] if fs == "ext2" else [False]
        for buf, sync in product(BUF_SIZES, sync_flags):
            compile_binary(buf, sync)
            drop_caches()
            real, user, sys_ = measure(inp, mnt)
            results[(fs, sync, buf)] = (real, user, sys_)
            print(f"  O_SYNC={'ON ' if sync else 'OFF'} buf={buf:>4}B  real={real:.3f}s  user={user:.3f}s  sys={sys_:.3f}s")
    finally:
        teardown_fs(img, mnt)

# --- 結果テーブル ---
col = 12
sep = "-" * (20 + col * len(BUF_SIZES))
print()
print(f"{'Filesystem':<10} {'O_SYNC':<5} {'':4}" + "".join(f"{'buf='+str(b)+'B':>{col}}" for b in BUF_SIZES))
print(sep)
for fs in FILESYSTEMS:
    for sync in [True, False]:
        if (fs, sync, BUF_SIZES[0]) not in results:
            continue
        label = "ON" if sync else "OFF"
        for kind, idx in [("real", 0), ("user", 1), ("sys", 2)]:
            row = f"{fs:<10} {label:<5} {kind:<4}"
            for buf in BUF_SIZES:
                row += f"{results[(fs,sync,buf)][idx]:.3f}s".rjust(col)
            print(row)
        print()
print(sep)

os.remove(BIN)

